mysql -u root -p"$MYSQL_PWD" maozz_pet <<'EOSQL'
INSERT INTO posts (user_id, title, content, post_type, category, tags, status, is_pinned, is_featured) VALUES
(1, '狗狗行为密码：5个常见"坏习惯"的科学纠正方法',
'<p>你的狗狗是否经常拆家、乱叫、扑人？这些让你头疼的行为，其实都有科学的解读和纠正方法。</p><h3>1. 拆家——分离焦虑的表现</h3><p>狗狗独处时疯狂破坏家具、门框，并非"调皮"，而是<strong>分离焦虑症</strong>的典型表现。研究表明，约<strong>20-40%</strong>的宠物犬存在不同程度的分离焦虑。</p><p><strong>纠正方法：</strong></p><ul><li>出门前不要过度告别，回家时保持平静，降低"出门"的仪式感</li><li>使用漏食玩具（如Kong）填充冻干零食，将出门变成"好事"的信号</li><li>逐步延长独处时间：从5分钟开始，慢慢增加到数小时</li><li>播放轻音乐或开启电视，提供背景音减少孤独感</li></ul><h3>2. 扑人——过度兴奋的社交方式</h3><p>狗狗扑人本质是表达兴奋和亲近，但对老人和小孩可能造成危险。</p><p><strong>纠正方法：</strong>当狗狗扑上来时，<strong>立刻转身背对它</strong>，双手交叉胸前，不给予任何关注。等它四脚着地安静下来后，再蹲下抚摸奖励。全家必须<strong>统一执行</strong>，否则训练无效。</p><h3>3. 暴冲——散步变成"被狗遛"</h3><p>拉力巨大的散步不仅影响体验，还可能导致颈椎损伤。</p><p><strong>纠正方法：</strong></p><ul><li>换用<strong>胸背式牵引带</strong>（非项圈），减少对气管的压力</li><li>狗狗拉紧牵引绳时，<strong>立刻停下来站住不动</strong>。绳子一松就继续走</li><li>每天短时间高频训练（3次x10分钟）优于一次长时间训练</li></ul><h3>4. 乱叫——情绪表达的出口</h3><p>首先需要区分叫声的含义：警惕性吠叫、索求性吠叫、焦虑性吠叫。</p><p><strong>警惕性吠叫</strong>：不要大喊"安静"（狗狗会认为你也在一起叫），而是引导它到窗边，平静地说"够了"，然后给它零食转移注意力。</p><p><strong>索求性吠叫</strong>：原则是<strong>完全无视</strong>。不看、不说、不碰。等它安静超过5秒后再给予关注。</p><h3>5. 吃便便——让主人崩溃的行为</h3><p>医学上称为"食粪症"，约16%的狗有过此行为。原因可能包括营养缺乏、行为模仿或注意力需求。</p><p><strong>纠正方法：</strong></p><ul><li>便后立即清理，不给机会</li><li>在食物中添加菠萝（含菠萝蛋白酶，使粪便味道变差）或益生菌</li><li>检查是否需要更换营养更均衡的狗粮</li></ul><blockquote>关键原则：所有行为纠正的核心是<strong>一致性</strong>和<strong>耐心</strong>。不存在3天见效的魔法，但坚持2-4周的科学训练，你一定会看到改变。</blockquote>',
 'knowledge', '狗狗训练', '狗狗行为,训练狗狗,宠物训练,狗狗拆家,分离焦虑,暴冲', 'published', 0, 1);

INSERT INTO posts (user_id, title, content, post_type, category, tags, status, is_pinned, is_featured) VALUES
(1, '夏日养宠安全手册：高温天气下的10个致命隐患与应对',
'<p>夏天是宠物最快乐的季节，也是最危险的季节。每年6-9月，宠物急诊量比其他季节高出<strong>40%以上</strong>。以下10个夏季隐患，每个铲屎官都必须知道。</p><h3>1. 中暑——头号杀手</h3><p>狗的正常体温为38-39.2°C，当体温超过<strong>41°C</strong>时即为中暑，超过<strong>42.7°C</strong>则可能致命。</p><p><strong>症状</strong>：剧烈喘息、流涎增多、牙龈发红、走路摇晃、呕吐、昏迷。</p><p><strong>紧急处理</strong>：立即移至阴凉处，用湿毛巾敷腋下和腹部（不要用冰水），用风扇吹风，<strong>15分钟内送医</strong>。</p><p><strong>预防</strong>：避免在10:00-16:00时段户外活动，永远不要把宠物留在车内（即使开窗，车内温度10分钟可升至47°C）。</p><h3>2. 烧伤路面</h3><p>气温30°C时，柏油路面温度可达<strong>60°C</strong>以上，足以在60秒内造成狗爪肉垫的三度烧伤。</p><p><strong>测试方法</strong>：将手背贴路面，<strong>无法坚持7秒=不适合遛狗</strong>。选择清晨或傍晚遛狗，必要时使用狗狗鞋子。</p><h3>3. 寄生虫高峰</h3><p>夏季是跳蚤、蜱虫的活跃高峰期。一只母蜱虫一次可产<strong>数千枚卵</strong>，一旦爆发，清除困难。</p><p><strong>对策</strong>：每月定期体外驱虫（推荐使用含有<strong>塞拉菌素</strong>或<strong>非泼罗尼</strong>成分的产品），每次户外活动后检查腋下、耳后、趾间是否有蜱虫附着。</p><h3>4. 空调病</h3><p>宠物长时间待在空调房，温度骤变易导致感冒和呼吸道问题。空调温度建议设定在<strong>25-27°C</strong>，避免冷风直吹宠物休息区域。</p><h3>5. 游水安全</h3><p>并非所有狗狗天生会游泳！巴哥犬、法斗、柯基等短鼻或短腿犬种容易溺水。<strong>务必使用宠物救生衣</strong>，第一次下水时在浅水区练习。</p><h3>6. 食物中毒</h3><p>夏季食物容易变质，户外烧烤后的骨头、腐败的水果都可能引起肠胃炎。外出时自带宠物饮水和零食，避免让狗狗捡食地面食物。</p><h3>7-10 其他隐患速查</h3><ul><li><strong>蚊虫叮咬</strong>：使用宠物专用驱蚊喷雾，人用驱蚊液对猫有毒（含菊酯类）</li><li><strong>草坪化学品</strong>：小区草坪的杀虫剂、除草剂可能导致中毒</li><li><strong>晒伤</strong>：白毛、薄毛、耳尖鼻头的宠物需要防晒，可用宠物专用防晒霜</li><li><strong>雷暴恐惧</strong>：约30%的狗惧怕雷声，提前准备安神用品或隔音空间</li></ul><blockquote>夏季养宠的核心原则：<strong>早出晚归、常驱虫、多观察、备应急</strong>。当你觉得热的时候，你的宠物可能比你更热。</blockquote>',
 'knowledge', '夏季养护', '夏季养宠,宠物安全,中暑,驱虫,蜱虫,宠物消暑', 'published', 0, 1);

INSERT INTO posts (user_id, title, content, post_type, category, tags, status, is_pinned, is_featured) VALUES
(1, '从流浪到被爱：一只橘猫改变了整个社区的温暖故事',
'<p>去年深秋的一个雨夜，小区垃圾桶旁多了一只瑟瑟发抖的橘猫。</p><h3>初遇：雨夜里的那双眼睛</h3><p>那天加班到深夜，回家路上看到一团湿漉漉的橘色蜷缩在垃圾桶旁。走近一看，是一只大约两三个月大的小橘猫，瘦得能摸到每一根肋骨，左耳有一道结痂的伤口。</p><p>它没有跑开，只是抬头看着我，那双琥珀色的眼睛里不是恐惧，而是一种让人心碎的疲惫。</p><p>那一刻，我做了这辈子最不理智的决定——打开纸箱，把它抱了回去。</p><h3>重生：从10天试探到30天信任</h3><p>最初三天，小橘猫——我给它取名<strong>"十月"</strong>（因为是十月捡到的）——藏在沙发底下不出来。我只在沙发旁放了一碗猫粮和一杯水，每天下班回来发现猫粮少了一些，就知道它偷偷出来吃过。</p><p>第七天，十月第一次在我面前出现。它小心翼翼地从沙发下探出半个头，然后——<strong>"喵"</strong>——轻轻叫了一声，仿佛在说"你是好人吗？"</p><p>第十天，它第一次跳上我的膝盖。那一刻，我感受到一个小小的身体在发抖，不是害怕，而是信任。</p><h3>涟漪：一只猫如何改变一个社区</h3><p>十月的到来，意外地改变了我们整个单元楼的氛围。</p><p>楼下养了15年狗的张大爷，第一次主动来敲门问我"猫好不好"，后来每天都会在楼道放一碟猫粮。</p><p>隔壁从来没打过招呼的年轻夫妇，因为十月跑到他们家门口晒太阳，开始和我聊天。</p><p>3楼的小女孩每天放学回来都会来"看看十月哥哥"，她妈妈说孩子自从认识了十月，变得更加温柔和有爱心。</p><p>我们单元楼甚至建了一个<strong>6人的"十月粉丝群"</strong>，轮流出猫粮、带十月打疫苗、寄养它主人出差时的日子。</p><h3>现在：温暖的日常</h3><p>一年过去了，十月从4斤长到了14斤（没错，橘猫的基因就是这么强大）。它有了自己的Instagram账号，粉丝比我还多。</p><p>它最喜欢的事：趴在窗台上看鸟（虽然永远抓不到）、凌晨3点在我枕头上踩奶、以及每周日陪张大爷散步。</p><p>张大爷说："自从有了十月，感觉自己年轻了十岁。"</p><blockquote>一只流浪猫的重量不到5公斤，但它能承载的温暖，是一个社区的。如果你也遇到了那个雨夜里的"十月"，请给它一个机会。你会发现，拯救它的同时，它也在治愈你。</blockquote>',
 'story', '温暖故事', '流浪猫,橘猫,领养,猫咪故事,宠物社区,治愈', 'published', 0, 1);

INSERT INTO posts (user_id, title, content, post_type, category, tags, status, is_pinned, is_featured) VALUES
(1, '2026年养宠好物年度推荐：这15件产品让养宠生活轻松10倍',
'<p>作为一个养了5年猫3年狗的"资深铲屎官"，我测试过上百款宠物用品。以下15款是经过时间验证的<strong>真正值得买</strong>的好物。</p><h3>一、喂食饮水类</h3><p><strong>1. 流动饮水机（推荐：小佩智能饮水机）</strong></p><p>猫咪天生偏好流动水源。使用饮水机后，我家猫的日均饮水量从<strong>80ml提升到200ml+</strong>。选择要点：静音、可拆洗、带滤芯。</p><p><strong>2. 定时自动喂食器（推荐：PETKIT Feed）</strong></p><p>上班族的刚需。可设置定时定量投喂，内置摄像头让你随时查看。出差时配合远程投喂功能，再也不用拜托邻居。</p><p><strong>3. 慢食碗/漏食碗</strong></p><p>进食过快会导致呕吐和消化不良。慢食碗通过迷宫设计让狗狗进食时间延长3-5倍，同时提供心理满足感。</p><h3>二、清洁护理类</h3><p><strong>4. 硅藻土猫砂垫</strong></p><p>放在猫砂盆门口，踩几下就能粘掉爪子上的猫砂碎粒。比传统脚垫好用10倍，清理只需抖一抖或水冲。</p><p><strong>5. 宠物专用湿巾</strong></p><p>日常擦爪子、擦屁股、清洁耳朵必备。选择<strong>无酒精、含芦荟</strong>的配方，温和不刺激。</p><p><strong>6. 针梳（推荐：Chris Christensen）</strong></p><p>长毛猫家庭必备。针梳能深入底层毛发，有效减少毛球症的发生，比普通梳毛刷效果好太多。</p><h3>三、娱乐运动类</h3><p><strong>7. KONG经典漏食玩具</strong></p><p>"狗狗时间管理器"。塞入花生酱+冻干后冻住，能让狗狗专注啃咬30-60分钟。分离焦虑和精力旺盛的狗狗必备。</p><p><strong>8. 逗猫棒套装</strong></p><p>一根好的逗猫棒胜过一百个电动玩具。选择羽毛+铃铛款，模拟飞鸟效果最吸引猫。每天15分钟逗猫，有效预防肥胖。</p><p><strong>9. 自动逗猫球</strong></p><p>工作不在家时的猫咪娱乐方案。选择<strong>不规则运动轨迹</strong>的产品，猫的好奇心能持续更久。</p><h3>四、健康安全类</h3><p><strong>10. 体外驱虫滴剂（推荐：大宠爱/福来恩）</strong></p><p>每月一次，沿脊椎滴在皮肤上。大宠爱还兼具体内驱虫功效，一箭双雕。选择渠道：正规宠物医院或官方旗舰店。</p><p><strong>11. GPS定位项圈</strong></p><p>带狗外出散步或旅行的安全神器。实时定位+电子围栏，狗狗超出范围自动报警。小型犬和猎犬尤其推荐。</p><p><strong>12. 宠物急救包</strong></p><p>包含纱布、碘伏、止血粉、嘴套、镊子（拔蜱虫用）。准备一个基本急救包，关键时刻能救命。</p><h3>五、生活便利类</h3><p><strong>13. 可折叠宠物水碗</strong></p><p>户外遛狗必备。硅胶材质，展开即用，折叠后只有名片大小，随身携带零负担。</p><p><strong>14. 宠物粘毛器</strong></p><p>养宠家庭的朋友来了再也不尴尬。选择<strong>可水洗型</strong>的，反复使用更环保省钱。</p><p><strong>15. 宠物摄像头（推荐：小米宠物摄像机）</strong></p><p>上班期间查看宠物动态，支持双向语音和零食投喂。价格亲民，功能齐全。</p><blockquote>养宠用品不需要全部买最贵的，但核心健康类产品（驱虫、猫粮、饮水机）一定不要省钱。好的用品不是消费，是对毛孩子健康的投资。</blockquote>',
 'knowledge', '好物推荐', '宠物好物,猫用品,狗用品,养宠必备,宠物推荐', 'published', 0, 1);

INSERT INTO posts (user_id, title, content, post_type, category, tags, status, is_pinned, is_featured) VALUES
(1, '养猫还是养狗？听听真实铲屎官的深度对比分析',
'<p>这大概是养宠圈子里永远讨论不完的话题。作为同时养猫又养狗的"双修选手"，我来从<strong>时间、金钱、空间、精力</strong>四个维度做一次真实对比。</p><h3>时间投入</h3><p><strong>狗狗</strong>是"高维护"宠物。每天至少需要<strong>2次遛狗</strong>（早晚各30-60分钟），加上喂食、梳毛、训练互动，日均投入<strong>2-3小时</strong>。周末基本被遛狗占领。</p><p><strong>猫咪</strong>是"低维护"宠物。自动喂食器+猫砂盆搞定日常，每天有效互动时间<strong>15-30分钟</strong>即可。出差3-5天内备足粮水猫砂即可。</p><p><strong>胜者：猫咪</strong></p><h3>金钱花费</h3><p><strong>初始投入</strong>：狗（5000-15000元购买+3000元用品）vs 猫（1000-8000元+1500元用品）</p><p><strong>月均花费</strong>：狗（500-1500元）vs 猫（200-600元）</p><p>大型犬月均花费更高，食量是猫的3-5倍。医疗费用方面，猫的绝育和疫苗费用通常低于狗。</p><p><strong>胜者：猫咪</strong></p><h3>空间需求</h3><p><strong>狗狗</strong>至少需要<strong>30㎡以上的活动空间</strong>，且需要靠近户外遛狗区域。高层公寓养中型以上犬有一定困难。</p><p><strong>猫咪</strong>在50㎡内就能过得很舒服，尤其适合楼房住户。垂直空间的利用（猫爬架、书架）可以大大扩展猫咪的活动范围。</p><p><strong>胜者：猫咪</strong></p><h3>情感互动</h3><p>这是<strong>狗狗完胜的领域</strong>。狗狗见到你时的兴奋程度、撒娇的方式、对你的无条件依赖，是猫咪很难企及的。狗狗会等你回家、陪你散步、在你难过时安静地靠过来。</p><p>但这不代表猫咪没有爱。猫咪的爱是<strong>安静的、克制的、选择性的</strong>。当一只猫选择跳上你的膝盖、对你慢慢眨眼时，那种被选中的独特感，是养狗体验中很难获得的。</p><p><strong>胜者：看你需要什么</strong></p><h3>生活自由度</h3><p>养狗意味着你的生活需要围绕狗狗的节奏来安排。不能临时决定周末出行，不能加班太晚，旅行需要安排寄养。</p><p>养猫则给你保留了大部分的生活自由度。</p><p><strong>胜者：猫咪</strong></p><h3>我的真心建议</h3><p>如果你是996上班族、经常出差、住公寓——<strong>选猫</strong>。</p><p>如果你时间充裕、热爱户外活动、渴望高密度的互动——<strong>选狗</strong>。</p><p>如果你和我一样两个都想要——恭喜你，你即将成为最忙碌也最幸福的铲屎官。</p><blockquote>无论选猫还是选狗，最重要的不是"哪个更好"，而是<strong>"哪个更适合你的生活方式"</strong>。宠物是15年的承诺，选择前请认真评估自己的时间和能力。</blockquote>',
 'forum', '养宠讨论', '养猫还是养狗,宠物选择,养宠对比,新手选宠', 'published', 0, 1);

EOSQL

echo "===== 5篇文章发布完成！ ====="
